create procedure sp_themsinhvien
    @masv varchar(20),
    @hoten nvarchar(50),
    @malop varchar(10),
    @gioitinh int,
    @ngaysinh date,
    @diachi nvarchar(100)
as
begin
    if exists (select * from dmlop where malop = @malop)
    begin
        insert into sinhvien (masv, hoten, malop, gioitinh, ngaysinh, diachi)
        values (@masv, @hoten, @malop, @gioitinh, @ngaysinh, @diachi)
        print 'them sinh vien thanh cong!'
    end
    else
    begin
        print 'ma lop khong ton tai, khong the them.'
    end
end

create procedure sp_themloai (
  @maloai int,
  @tenloai nvarchar(50),
  @mota nvarchar(max)
) as begin
insert into
  loai (maloai, tenloai, mota)
values
  (@maloai, @tenloai, @mota) end

-- Thực thi procedure
EXEC sp_themloai 100, N'Loại mới', N'Mô tả';

create procedure sp_sualoai (
  @maloai int,
  @tenloai nvarchar(50),
  @mota nvarchar(max)
) as begin
update loai
set
  tenloai = @tenloai,
  mota = @mota
where
  maloai = @maloai end

-- Thực thi procedure
EXEC sp_sualoai 1, N'Tên loại sửa', N'Mô tả sửa';
